snippet.sync_client:
package com.example.usage;

import com.seed.api.SeedApiClient;
import com.seed.api.requests.CreateItemRequest;

public class Example {
    public static void main(String[] args) {
        SeedApiClient client = SeedApiClient
            .builder()
            .build();

        client.createItem(
            "key",
            "value",
            CreateItemRequest
                .builder()
                .data("data")
                .build()
        );
    }
}

